(function(){"use strict";var API_URL=window.location.origin+"/api";async function fetchJSON(endpoint){var res=await fetch(API_URL+endpoint);if(!res.ok)throw new Error("HTTP "+res.status);return res.json()}async function getSiteData(){return fetchJSON("/site")}async function getSiteVersion(){try{var data=await fetchJSON("/site/version");return data.version!=null?data.version:data}catch(e){return null}}window.api={apiUrl:API_URL,API_URL:API_URL,getEvents:function(){return fetchJSON("/events")},getGallery:function(){return fetchJSON("/gallery")},getSiteData:getSiteData,getSiteVersion:getSiteVersion}})();